"""Security Testing Utilities for Mario Assistant Vocal.

Testing input validation, XSS prevention, path traversal protection,
sanitization, and rate limiting.

Tests follow OWASP Input Validation and Sanitization Cheat Sheet patterns.
"""

import re
import unicodedata
from typing import Tuple, List
from pathlib import Path
import time


def validate_input_length(text: str, max_words: int = 1000) -> Tuple[bool, str]:
    """Validate input doesn't exceed word limit."""
    if text is None:
        return False, "Input is None"
    words = text.split()
    if len(words) > max_words:
        return False, f"Too many words: {len(words)} > {max_words}"
    return True, "Valid"


def sanitize_html_input(text: str) -> str:
    """Strip all HTML tags from input."""
    if text is None:
        return ""
    text = str(text)
    cleaner = re.compile('<[^<]+>')
    return re.sub(cleaner, '', text)


def strip_html_tags(text: str) -> str:
    """Pure HTML tag stripping function."""
    return sanitize_html_input(text)


def escape_special_chars(text: str) -> str:
    """Escape special HTML chars: < > & " '"""
    if text is None:
        return ""
    text = str(text)
    text = text.replace('&', '&amp;')
    text = text.replace('<', '&lt;')
    text = text.replace('>', '&gt;')
    text = text.replace('"', '&quot;')
    text = text.replace("'", '&#x27;')
    return text


def normalize_unicode_text(text: str) -> str:
    """Normalize unicode to NFC form."""
    if text is None:
        return ""
    return unicodedata.normalize('NFC', str(text))


def sanitize_file_path(path: str, base_dir: Path = None) -> Tuple[bool, str]:
    """Validate file path doesn't contain traversal attempts."""
    if path is None:
        return False, "Path is None"

    path_str = str(path)

    # Check for path traversal patterns
    if '..' in path_str or path_str.startswith('/') or path_str.startswith('\\'):
        return False, "Invalid path: contains traversal or absolute path"

    # Use pathlib for safe resolution
    if base_dir:
        try:
            resolved = (base_dir / path_str).resolve()
            if not str(resolved).startswith(str(base_dir)):
                return False, "Path traversal detected"
            return True, str(resolved)
        except Exception:
            return False, "Invalid path resolution"

    # Basic validation
    if path_str.count('/') > 5 or path_str.count('\\') > 5:
        return False, "Too many path separators"

    return True, path_str


def sanitize_conversation_message(text: str) -> str:
    """Sanitize conversation message - strip HTML and normalize."""
    text = sanitize_html_input(str(text))
    text = normalize_unicode_text(text)
    return text.strip()


def strip_unsafe_chars(text: str) -> str:
    """Remove control characters and unsafe unicode."""
    if text is None:
        return ""

    text = str(text)
    result = []

    for char in text:
        category = unicodedata.category(char)
        # Keep printable chars, allow normal spaces
        if category.startswith('C') and char not in [' ', '\n', '\t']:
            continue
        result.append(char)

    return ''.join(result)


def sanitize_json_string(text: str) -> str:
    """Prepare string for safe JSON embedding."""
    text = escape_special_chars(str(text))
    text = strip_unsafe_chars(text)
    return text


class SimpleRateLimiter:
    """Basic token bucket rate limiter for API protection."""

    def __init__(self, max_requests: int = 100, window_seconds: int = 60):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.requests: List[float] = []

    def is_allowed(self, client_id: str = "default") -> Tuple[bool, int]:
        """Check if request is allowed."""
        now = time.monotonic()

        # Clean old requests
        self.requests = [r for r in self.requests if now - r < self.window_seconds]

        # Check limit
        if len(self.requests) >= self.max_requests:
            return False, 0

        # Allow request
        self.requests.append(now)
        remaining = self.max_requests - len(self.requests)
        return True, remaining


def detect_abuse_patterns(text: str) -> Tuple[bool, str]:
    """Detect potential injection or abuse patterns."""
    if text is None:
        return False, "Text is None"

    text_lower = str(text).lower()

    # SQL keywords
    sql_keywords = ['union', 'select', 'drop', 'insert', 'delete', '--']
    for keyword in sql_keywords:
        if keyword in text_lower:
            return False, f"Potential SQL injection: {keyword}"

    # Script injection
    script_keywords = ['<script', 'javascript:', 'onerror=', 'onload=']
    for keyword in script_keywords:
        if keyword in text_lower:
            return False, f"Potential XSS: {keyword}"

    # Path traversal
    if '..' in text:
        return False, "Potential path traversal"

    return True, "No abuse detected"

